import React, { useState } from 'react';
import LanguageSwitcher from './LanguageSwitcher';

function Profile({ user, onUpdate, onBack }) {
  const [name, setName] = useState(user?.name || '');
  const [age, setAge] = useState(user?.age || '');
  const [city, setCity] = useState(user?.city || '');
  const [bio, setBio] = useState(user?.bio || '');
  const [profilePic, setProfilePic] = useState(user?.profilePic || null);

  const handleImageUpload = (e) => {
    const file = e.target.files[0];
    if (file) {
      if (file.size > 2 * 1024 * 1024) return alert('❌ Image trop grande (max 2 Mo)');
      const reader = new FileReader();
      reader.onload = (e) => setProfilePic(e.target.result);
      reader.readAsDataURL(file);
    }
  };

  const handleSave = () => {
    if (!name || !age || !city) return alert('❌ Veuillez remplir tous les champs');
    const updatedUser = { ...user, name, age: parseInt(age), city, bio, profilePic };
    alert('✅ Profil mis à jour');
    onUpdate(updatedUser);
    onBack();
  };

  return (
    <div style={styles.container}>
      <div style={styles.card}>
        <button style={styles.backBtn} onClick={onBack}>← Retour</button>
        <h1 style={styles.title}>👤 Mon Profil</h1>
        <LanguageSwitcher />
        <div style={styles.imageContainer}>
          {profilePic ? <img src={profilePic} alt="Profile" style={styles.profileImage} /> : <div style={styles.profilePlaceholder}>📸</div>}
          <label style={styles.uploadBtn}>📷 Changer la photo<input type="file" accept="image/*" onChange={handleImageUpload} style={styles.fileInput} /></label>
        </div>
        <input type="text" placeholder="👤 Nom" value={name} onChange={(e) => setName(e.target.value)} style={styles.input} />
        <input type="number" placeholder="🎂 Âge" value={age} onChange={(e) => setAge(e.target.value)} style={styles.input} />
        <input type="text" placeholder="📍 Ville" value={city} onChange={(e) => setCity(e.target.value)} style={styles.input} />
        <textarea placeholder="💕 Bio" value={bio} onChange={(e) => setBio(e.target.value)} style={styles.textarea} rows="3" />
        <button style={styles.saveBtn} onClick={handleSave}>💾 Enregistrer</button>
      </div>
    </div>
  );
}

const styles = {
  container: { display: 'flex', justifyContent: 'center', alignItems: 'center', minHeight: '100vh', background: 'linear-gradient(135deg, #FFB6C1, #87CEEB)', padding: 20 },
  card: { backgroundColor: 'white', padding: 40, borderRadius: 24, maxWidth: 450, width: '100%', textAlign: 'center', position: 'relative' },
  backBtn: { position: 'absolute', top: 15, left: 20, background: 'none', border: 'none', fontSize: '1.2rem', cursor: 'pointer', color: '#888', fontWeight: 'bold' },
  title: { fontSize: '2rem', background: 'linear-gradient(45deg, #FF69B4, #4A90D9)', WebkitBackgroundClip: 'text', WebkitTextFillColor: 'transparent', marginBottom: 15 },
  imageContainer: { display: 'flex', flexDirection: 'column', alignItems: 'center', marginBottom: 20 },
  profileImage: { width: 120, height: 120, borderRadius: '50%', objectFit: 'cover', border: '4px solid #FF69B4' },
  profilePlaceholder: { width: 120, height: 120, borderRadius: '50%', backgroundColor: '#f0f0f0', display: 'flex', justifyContent: 'center', alignItems: 'center', border: '4px solid #FF69B4', fontSize: 50 },
  uploadBtn: { marginTop: 10, padding: '10px 20px', backgroundColor: '#f0f0f0', borderRadius: 10, cursor: 'pointer', fontSize: '0.9rem', fontWeight: 'bold', color: '#555' },
  fileInput: { display: 'none' },
  input: { width: '100%', padding: 12, margin: '10px 0', borderRadius: 12, border: '2px solid #ddd', fontSize: '1rem', boxSizing: 'border-box' },
  textarea: { width: '100%', padding: 12, margin: '10px 0', borderRadius: 12, border: '2px solid #ddd', fontSize: '1rem', boxSizing: 'border-box', resize: 'vertical', fontFamily: 'Arial' },
  saveBtn: { width: '100%', padding: 14, marginTop: 20, borderRadius: 12, border: 'none', background: 'linear-gradient(45deg, #FF6B6B, #FF1493)', color: 'white', fontSize: '1.2rem', fontWeight: 'bold', cursor: 'pointer' },
};

export default Profile;
